struct Guard<'a>(pub &'a str);

// '_ in return position connects to the single input lifetime (elision rule 3)
// These three are equivalent:
fn explicit<'a>(input: &'a str) -> Guard<'a> {
    Guard(input)
}

fn with_named<'a>(input: &'a str) -> Guard<'_> {  // '_ = 'a (only one option)
    Guard(input)
}

fn fully_elided(input: &str) -> Guard<'_> {  // '_ inferred from &str input
    Guard(input)
}

// When '_ is AMBIGUOUS (multiple input lifetimes), the compiler asks you to be explicit
fn choose_lifetime<'a, 'b>(a: &'a str, _b: &'b str) -> Guard<'a> {
    Guard(a)  // must name 'a explicitly — '_ would be ambiguous
}

// In let bindings '_ is "hole" — compiler fills it in from the type of the value
fn binding_examples() {
    let s = String::from("hello");
    let g: Guard<'_> = Guard(&s);  // '_ inferred = lifetime of &s
    println!("{}", g.0);
    // g lives until here, so &s borrow ends here
}

fn main() {
    let s = String::from("test");
    let g1 = explicit(&s);
    let g2 = with_named(&s);
    let g3 = fully_elided(&s);
    println!("{} {} {}", g1.0, g2.0, g3.0);
    binding_examples();
}

