use serde::{Deserialize, de};

#[derive(Deserialize, Debug)]
struct Record<'de> {
    name: &'de str,
    value: &'de str,
}

struct RecordVisitor;

impl<'de> de::Visitor<'de> for RecordVisitor {
    type Value = Record<'de>;

    // Formatter<'_> is required: Formatter has a lifetime parameter
    fn expecting(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "a record with name and value")
    }

    fn visit_map<A: de::MapAccess<'de>>(self, mut map: A)
        -> Result<Record<'de>, A::Error>
    {
        let mut name = None;
        let mut value = None;
        while let Some(key) = map.next_key::<&str>()? {
            match key {
                "name" => name = Some(map.next_value()?),
                "value" => value = Some(map.next_value()?),
                _ => { map.next_value::<de::IgnoredAny>()?; }
            }
        }
        Ok(Record {
            name: name.ok_or_else(|| de::Error::missing_field("name"))?,
            value: value.ok_or_else(|| de::Error::missing_field("value"))?,
        })
    }
}

fn main() {
    let json = r#"{"name":"Alice","value":"42"}"#;
    let r: Record<'_> = serde_json::from_str(json).unwrap();
    println!("{:?}", r);
}

